**Risk**: SQL injection, NoSQL injection, command injection, XSS if data is reflected back.

**Recommendation**:
```javascript
// Before: No validation
app.get('/users', (req, res) => {
  res.json([...]);
});

// After: With validation
const { query, validationResult } = require('express-validator');

app.get('/users', 
  query('id').optional().isInt().toInt(),
  query('search').optional().trim().escape(),
  (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }
    res.json([...]);
  }
);
```

---

#### **2. Missing Security Headers** ⚠️
**Issue**: No HTTP security headers configured (HSTS, CSP, X-Frame-Options, etc.)

**Risk**: Clickjacking, man-in-the-middle attacks, XSS attacks, MIME-type sniffing.

**Recommendation**:
```javascript
const helmet = require('helmet');

// Add this early in middleware chain
app.use(helmet());

// Or manually set headers:
app.use((req, res, next) => {
  res.setHeader('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
  res.setHeader('X-Content-Type-Options', 'nosniff');
  res.setHeader('X-Frame-Options', 'DENY');
  res.setHeader('Content-Security-Policy', "default-src 'self'");
  res.setHeader('X-XSS-Protection', '1; mode=block');
  next();
});
```

---

#### **3. Missing Rate Limiting** ⚠️
**Issue**: No protection against brute force or DoS attacks.

**Risk**: Attackers can flood endpoints, causing denial of service.

**Recommendation**:
```javascript
const rateLimit = require('express-rate-limit');

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true,
  legacyHeaders: false,
});

app.use(limiter);

// Or stricter for sensitive endpoints:
const strictLimiter = rateLimit({
  windowMs: 1 * 60 * 1000, // 1 minute
  max: 5, // Very strict
});

app.get('/users', strictLimiter, (req, res) => {
  res.json([...]);
});
```

---

#### **4. No Authentication/Authorization** ⚠️
**Issue**: `/users` endpoint returns sensitive data without any access control.

**Risk**: Unauthorized access to user information. **OWASP A01:2021 - Broken Access Control**.

**Recommendation**:
```javascript
const jwt = require('jsonwebtoken');

// Middleware to verify JWT
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) return res.sendStatus(401);

  jwt.verify(token, process.env.JWT_SECRET, (err, user) => {
    if (err) return res.sendStatus(403);
    req.user = user;
    next();
  });
};

app.get('/users', authenticateToken, (req, res) => {
  res.json([...]);
});
```

