    return res.sendStatus(403);
  }
  // Return email only to owner
  res.json({ email: 'user@example.com' });
});
```

---

#### **8. Missing Environment Configuration** ⚠️
**Issue**: Hardcoded port, no secrets management.

**Risk**: Configuration exposed in source code, secrets in version control.

**Recommendation**:
```javascript
require('dotenv').config();

const PORT = process.env.PORT || 3000;
const NODE_ENV = process.env.NODE_ENV || 'development';

// Ensure critical env vars are set
if (NODE_ENV === 'production' && !process.env.JWT_SECRET) {
  throw new Error('JWT_SECRET must be set in production');
}

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT} (${NODE_ENV})`);
});
```

---

#### **9. No Error Handling** ⚠️
**Issue**: No try-catch or error middleware.

**Risk**: Unhandled exceptions crash the server, exposing stack traces to clients.

**Recommendation**:
```javascript
app.get('/users', authenticateToken, (req, res, next) => {
  try {
    // Add error handling
