      { id: 1, name: 'Alice' },
      { id: 2, name: 'Bob' },
    ];
    res.json(users);
  } catch (error) {
    next(error); // Pass to error handler
  }
});

// Global error handler
app.use((err, req, res, next) => {
  console.error(err);
  res.status(500).json({ error: 'Internal Server Error' });
});
